#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int K, M, w;
        scanf("%d %d %d", &K, &M, &w);
        int* l = (int*)malloc(K * sizeof(int));
        int* h = (int*)malloc(K * sizeof(int));
        for (int j = 0; j < K; j++) {
            scanf("%d %d", &l[j], &h[j]);
        }
        long long int** dp = (long long int**)malloc(K * sizeof(long long int*));
        for (int j = 0; j < K; j++) {
            dp[j] = (long long int*)malloc(M * sizeof(long long int));
        }
        for (int j = 0; j < K; j++) {
            for (int k = 0; k < M; k++) {
                if (j == 0) {
                    dp[j][k] = 0;
                } else if (k == 0) {
                    dp[j][k] = (long long int)l[j-1] * h[j-1] * w;
                } else {
                    long long int min = (long long int)1e18;
                    for (int prev = 0; prev < j; prev++) {
                        min = (min < dp[prev][k-1] + (long long int)l[j-1] * h[j-1] * w) ? min : dp[prev][k-1] + (long long int)l[j-1] * h[j-1] * w;
                    }
                    dp[j][k] = min;
                }
            }
        }
        long long int min = (long long int)1e18;
        for (int j = 0; j < M; j++) {
            min = (min < dp[K-1][j]) ? min : dp[K-1][j];
        }
        printf("Case %d: %lld\n", i+1, min);
        free(l);
        free(h);
        for (int j = 0; j < K; j++) {
            free(dp[j]);
        }
        free(dp);
    }
    return 0;
}

