code.Java:
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int i = 0; i < T; i++) {
            int K = sc.nextInt();
            int M = sc.nextInt();
            int w = sc.nextInt();
            int[] l = new int[K];
            int[] h = new int[K];
            for (int j = 0; j < K; j++) {
                l[j] = sc.nextInt();
                h[j] = sc.nextInt();
            }
            long[][] dp = new long[K][M];
            for (int j = 0; j < K; j++) {
                for (int k = 0; k < M; k++) {
                    if (j == 0) {
                        dp[j][k] = 0;
                    } else if (k == 0) {
                        dp[j][k] = (long)l[j-1] * h[j-1] * w;
                    } else {
                        long min = Long.MAX_VALUE;
                        for (int prev = 0; prev < j; prev++) {
                            min = Math.min(min, dp[prev][k-1] + (long)l[j-1] * h[j-1] * w);
                        }
                        dp[j][k] = min;
                    }
                }
            }
            long min = Long.MAX_VALUE;
            for (int j = 0; j < M; j++) {
                min = Math.min(min, dp[K-1][j]);
            }
            System.out.println("Case " + (i+1) + ": " + min);
        }
    }
}

